import React from 'react'
import Star from './Star'
import useState from 'react'

function StarRate() {
  return (
    <div>
    {
      [... new Array(5)].map((star, index)=>{
        return <a href="#"><Star position = {index} rate={3}/></a>
      })
    }
   </div>
  )
}

export default StarRate
